import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';

const BallyGamboyGame = () => {
    const gameRef = useRef(null);
    let player;

    useEffect(() => {
        const initializeGame = () => {
            const config = {
                type: Phaser.AUTO,
                width: 800,
                height: 600,
                scene: {
                    preload: preload,
                    create: create
                },
                physics: {
                    default: 'arcade',
                    arcade: {
                        gravity: { y: 0 },
                        debug: false
                    }
                }
            };

            gameRef.current = new Phaser.Game(config);
        };

        function preload() {
            this.load.image('player', './phaser-resources/images/player.png');
            this.load.image('background', './phaser-resources/images/background.png');
            this.load.image('upButton', './phaser-resources/images/upButton.png');
            this.load.image('downButton', './phaser-resources/images/downButton.png');
            this.load.image('leftButton', './phaser-resources/images/leftButton.png');
            this.load.image('rightButton', './phaser-resources/images/rightButton.png');
        }

        function create() {
            // Create the background sprite
            const background = this.add.sprite(0, 0, 'background').setOrigin(0);

            // Load player sprite
            player = this.physics.add.sprite(400, 300, 'player');

            // Create directional pad buttons
            this.upButton = this.add.sprite(750, 250, 'upButton');
            this.downButton = this.add.sprite(750, 350, 'downButton');
            this.leftButton = this.add.sprite(700, 300, 'leftButton');
            this.rightButton = this.add.sprite(800, 300, 'rightButton');

            // Make buttons interactive
            this.upButton.setInteractive();
            this.downButton.setInteractive();
            this.leftButton.setInteractive();
            this.rightButton.setInteractive();

            // Listen for pointer down events on each button
            this.upButton.on('pointerdown', () => movePlayer('up'));
            this.downButton.on('pointerdown', () => movePlayer('down'));
            this.leftButton.on('pointerdown', () => movePlayer('left'));
            this.rightButton.on('pointerdown', () => movePlayer('right'));
        }

        function movePlayer(direction) {
            const distance = 200;
            let destinationX = player.x;
            let destinationY = player.y;

            switch (direction) {
                case 'up':
                    destinationY -= distance;
                    break;
                case 'down':
                    destinationY += distance;
                    break;
                case 'left':
                    destinationX -= distance;
                    break;
                case 'right':
                    destinationX += distance;
                    break;
                default:
                    break;
            }

            // Tween the player sprite to the destination coordinates
            gameRef.current.tweens.add({
                targets: player,
                x: destinationX,
                y: destinationY,
                duration: 500, // Duration of the tween animation in milliseconds
                ease: 'Linear', // Easing function
            });
        }

        initializeGame();

        return () => {
            if (gameRef.current) {
                gameRef.current.destroy(true);
            }
        };
    }, []);

    return <div id="ballygamboy-game-container"></div>;
};

export default BallyGamboyGame;
